#pragma once
#define BATTERIES_SEQ_AS_SEQ_HPP

#include <batteries/config.hpp>
//
#include <batteries/seq/sub_range_seq.hpp>

#include <batteries/slice.hpp>

#include <boost/range/iterator_range.hpp>

#include <type_traits>
#if BATT_CPP_20
#include <ranges>
#endif  // BATT_CPP_20

namespace batt {

template <typename ForwardIter>
auto as_seq(ForwardIter&& begin, ForwardIter&& end)
{
    return as_seq(boost::make_iterator_range(BATT_FORWARD(begin), BATT_FORWARD(end)));
}

template <typename VectorLike, typename = decltype(std::declval<VectorLike>().data()),
          typename = decltype(std::declval<VectorLike>().size()),
          typename = std::enable_if_t<std::is_same_v<decltype(std::declval<VectorLike>().data()),
                                                     decltype(std::declval<VectorLike>().data() +
                                                              std::declval<VectorLike>().size())>>>
auto as_seq(VectorLike&& v)
{
    return as_seq(v.data(), v.data() + v.size());
}

#if BATT_CPP_20

template <typename IterT>
auto as_seq(const std::ranges::subrange<IterT>& r)
{
    return as_seq(r.begin(), r.end());
}

#endif  // BATT_CPP_20

template <typename T>
SubRangeSeq<Slice<T>> as_seq(const Slice<T>& s)
{
    return SubRangeSeq<Slice<T>>{batt::make_copy(s)};
}

template <typename T>
auto as_seq(Slice<T>& s)
{
    return as_seq(const_cast<const Slice<T>&>(s));
}

template <typename T>
auto as_seq(Slice<T>&& s)
{
    return as_seq(const_cast<const Slice<T>&>(s));
}

template <typename T>
auto as_seq(const Slice<T>&& s)
{
    return as_seq(const_cast<const Slice<T>&>(s));
}

}  //namespace batt
